#include<cstdio>
#include<iostream>
#include<algorithm>
#include<deque>
#define int long long
using namespace std;

const int N = 1e5 + 5;

int a[N], s[N], f[N][2];
deque<int> q;

signed main(){
    int n, k;
	cin >> n >> k;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
    for(int i = 1; i <= n; i++)
		s[i] = s[i - 1] + a[i];
    q.push_back(-1e9);
	for(int i = 1; i <= n; i++){
        f[i][0] = max(f[i - 1][0], f[i - 1][1]);
        while(!q.empty() && q.front() < i - k) q.pop_front();
        f[i][1] = f[q.front()][0] - s[q.front()] + s[i];
        while(!q.empty() && f[q.back()][0] - s[q.back()] <= f[i][0] - s[i]) q.pop_back();
        q.push_back(i);
    }
	cout << max(f[n][0], f[n][1]);
	return 0;
}
